COMPLEX16 calculate_h44FourierMode_zeroe(REAL8 eta, DynParamsCache *dc)
{
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];

#define CPREF 0.8451542547285165775096183273659452926307858901134771889828170956
    REAL8 PN2 = CPREF*(16*(-1. + 3.*eta))/9.;
    REAL8 PN4 = CPREF*(8*(1779. - 6365.*eta + 2625.*eta2))/1485.;
    REAL8 ImPN5 = CPREF*(-124.*eta)/15.;
    REAL8 PN6 = CPREF*(2*(-9618039. + 68551497.*eta - 113096830.*eta2 + 23740185.*eta3))/2027025.;

    REAL8 lnxOx0p = log(v2/CONST_X0P);
    COMPLEX16 PN5_tail = CPREF*(-21.*I + 30.*I*lnxOx0p + 10.*CST_PI + 20.*I*CST_LN2)*(-1.+3.*eta)*16./45.;
    return v2*(PN2 + 
                v2*(PN4 + 
                    v*(I*ImPN5 + PN5_tail + 
                        v*PN6)));
#undef CPREF
}

