COMPLEX16 calculate_h42FourierMode_zeroe(REAL8 eta, DynParamsCache *dc)
{
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];

#define CPREF 2.236067977499789696409173668731276235440618359611525724270897245
    REAL8 PN2 = CPREF*(-2.*(-1. + 3.*eta))/63.;
    REAL8 PN4 = CPREF*(-1311. + 4025.*eta - 285.*eta2)/10395.;
    REAL8 ImPN5 = CPREF*(2.*eta)/15.;
    REAL8 PN6 = CPREF*(9342351. - 38225313.*eta + 28031710.*eta2 + 2707215.*eta3)/56756700.;

    REAL8 lnxOx0p = log(v2/CONST_X0P);
    COMPLEX16 PN5_tail = -CPREF*(-21.*I + 30.*I*lnxOx0p + 10.*CST_PI)*(-1.+3.*eta)/315.;
    return v2*(PN2 + 
                v2*(PN4 + 
                    v*(I*ImPN5 + PN5_tail + 
                        v*PN6)));
#undef CPREF
}

