COMPLEX16 calculate_h40FourierModep(INT p, REAL8 eta, DynParamsCache *dc, PNEllipticEvaluator *pe)
{
    COMPLEX16 ret;
    INT pm = p;
    if (pm==0) return 0.0;
    INT pm2 = pm*pm;
    INT pm3 = pm2*pm;
    INT pm4 = pm2*pm2;
    INT pm5 = pm4*pm;
    REAL8 *ePow = dc->ePow;
    REAL8 *sq1m2Pow = dc->sq1mesqPow;
    REAL8 m1p3eta = -1. + 3.*eta;
    REAL8 y = sq1m2Pow[1];
    REAL8 yp = y+1.0, myp = -y+1.0;
    REAL8 yp2 = yp*yp, myp2 = myp*myp;
    REAL8 yp3 = yp2*yp, myp3 = myp2*myp;
    REAL8 yp4 = yp3*yp, myp4 = myp3*myp;
    REAL8 yp5 = yp4*yp, myp5 = myp4*myp;
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
#define EVALEJ(pp, qq, aa, bb) evaluate_Jpqab((pp), (qq), (aa), (bb), pe)
// #define EVALEJ(p, q, a, b) 1.0
#define SQ1M2(n) sq1m2Pow[n]
#define EPOW(n) ePow[n]
    REAL8 PN2, PN4, ImPN5, PN6;
    PN2 = -6*EVALEJ(pm,pm,0,0) - 5*EVALEJ(pm,pm,1,0) + 5*EVALEJ(pm,pm,2,0)*SQ1M2(2);
    PN2 *= CST_SQRT1_2 * m1p3eta / (42.);

    PN4 = EVALEJ(pm,pm,1,0)*(-20 + 60*eta + ((222 - 689*eta + 33*eta2)*SQ1M2(2))/6.) + 
    EVALEJ(pm,pm,0,0)*(-24 + 72*eta + ((195 - 623*eta + 51*eta2)*SQ1M2(2))/11.) - 
    (5*(497 - 1528*eta + 76*eta2)*EVALEJ(pm,pm,3,0)*SQ1M2(4))/44. + 
    EVALEJ(pm,pm,2,0)*((20 - 60*eta)*SQ1M2(2) - 
    ((951 - 2995*eta + 135*eta2)*SQ1M2(4))/66.) + 
    (3*(497 - 1528*eta + 76*eta2)*EVALEJ(pm,pm,4,0)*SQ1M2(6))/44.;    
    PN4 *= CST_SQRT1_2/(42.*sq1m2Pow[2]);

    ImPN5 = (-39*pm*EVALEJ(pm,pm,0,0))/5. - (3*pm*EVALEJ(pm,pm,1,0))/10. + 
    (9*pm*EVALEJ(pm,pm,2,0)*SQ1M2(2))/2.;   
    ImPN5 *= CST_SQRT1_2*eta/42.;

    PN6 = (9*(5 - 17*eta + 6*eta2)*pm*EPOW(1)*EVALEJ(-1 + pm,pm,0,1)*SQ1M2(3))/2. + 
        (15*(5 - 17*eta + 6*eta2)*pm*EVALEJ(pm,pm,1,1)*SQ1M2(3))/2. + 
        (9*(5 - 17*eta + 6*eta2)*pm*EPOW(1)*EVALEJ(1 + pm,pm,0,1)*SQ1M2(3))/2. + 
        (3*eta*(15 - 46*eta + 3*eta2)*pm*EPOW(1)*EVALEJ(-1 + pm,pm,0,0)*SQ1M2(4))/4. - 
        (3*eta*(15 - 46*eta + 3*eta2)*pm*EPOW(1)*EVALEJ(-1 + pm,pm,1,0)*SQ1M2(4))/8. + 
        (3*eta*(15 - 46*eta + 3*eta2)*pm*EPOW(1)*EVALEJ(1 + pm,pm,1,0)*SQ1M2(4))/8. + 
        EVALEJ(pm,pm,0,0)*(-18*(7 - 27*eta + 18*eta2) + 
        (2*(-24 - 100*eta + 705*eta2)*SQ1M2(2))/11. + 
        12*(5 - 17*eta + 6*eta2)*SQ1M2(3) - 
        ((-96570 + 15*eta*(24058 + 2574*pm + 2145*pm2) + 
        eta3*(-8850 + 7722*pm + 6435*pm2) - 
        2*eta2*(66394 + 59202*pm + 49335*pm2))*SQ1M2(4))/3432.) - 
        (15*(5 - 17*eta + 6*eta2)*pm*EVALEJ(pm,pm,2,1)*SQ1M2(5))/2. - 
        (EVALEJ(pm,pm,4,0)*(7024720 - 24218838*eta + 9108204*eta2 - 557018*eta3 + 
        21*(-64183 + 196353*eta + 960*eta2 + 9296*eta3)*SQ1M2(2))*SQ1M2(6))/24024.\
        + EVALEJ(pm,pm,3,0)*(-0.0016233766233766235*
        ((-62968 + 166649*eta + 51170*eta2 + 32375*eta3)*SQ1M2(4)) - 
        15*(5 - 17*eta + 6*eta2)*SQ1M2(5) - 
        (3*(218463 - 660854*eta - 81850*eta2 + 17265*eta3)*SQ1M2(6))/5720.) + 
        EVALEJ(pm,pm,2,0)*(15*(7 - 27*eta + 18*eta2)*SQ1M2(2) + 
        (45*(5 - 17*eta + 6*eta2)*SQ1M2(3))/2. + 
        ((478428 - 1527379*eta + 174930*eta2 + 32970*eta3)*SQ1M2(4))/2310. - 
        (5*(5 - 17*eta + 6*eta2)*SQ1M2(5))/2. - 
        ((221409 - 676185*eta - 164938*eta2 + 69339*eta3)*SQ1M2(6))/10296.) + 
        EVALEJ(pm,pm,1,0)*(-15*(7 - 27*eta + 18*eta2) + 
        (-113 + (830*eta)/3. + 223*eta2)*SQ1M2(2) - 
        5*(5 - 17*eta + 6*eta2)*SQ1M2(3) + 
        ((1335807 - 2762301*eta - 6123710*eta2 + 815325*eta3)*SQ1M2(4))/51480. + 
        (5*eta*(15 - 46*eta + 3*eta2)*pm2*SQ1M2(6))/16.) + 
        ((592636 - 2096649*eta + 680568*eta2 + 158500*eta3)*EVALEJ(pm,pm,5,0)*SQ1M2(8))/
        3432. - ((25828 - 81099*eta - 29760*eta2 + 26320*eta3)*EVALEJ(pm,pm,6,0)*
        SQ1M2(10))/1144.;
    PN6 *= CST_SQRT1_2 / (42.*sq1m2Pow[4]);

    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];

    // tail part
    COMPLEX16 PN5_tail;
    COMPLEX16 lnIpvO2 =  pm>0 ? (log(0.5*pm) + 0.5*I*CST_PI) : (log(-0.5*pm) - 0.5*I*CST_PI);
    REAL8 lnxOx0p = log(v2/CONST_X0P);
    COMPLEX16 pref_tail;
    pref_tail = -21. + 30.*lnxOx0p + 20.*lnIpvO2;
    PN5_tail = (3*EVALEJ(pm,pm,2,0))/5. + (35*EVALEJ(pm,pm,5,0)*SQ1M2(2))/4. - 
        (7*EVALEJ(pm,pm,4,0)*(5 + 3*SQ1M2(2)))/10. - (15*EVALEJ(pm,pm,6,0)*SQ1M2(4))/4.;
    PN5_tail *= I * CST_SQRT1_2 * m1p3eta * pref_tail / (pm*42.);

    // print_debug("PN2 = %.16e\n", v2*PN2);
    // print_debug("PN4 = %.16e\n", dc->vPow[4]*PN4);
    // print_debug("ImPN5 = %.16e\n", dc->vPow[5]*ImPN5);
    // print_debug("PN6 = %.16e\n", dc->vPow[6]*PN6);
    // print_debug("PN5_tail = %.16e, %.16e\n", dc->vPow[5]*creal(PN5_tail), dc->vPow[5]*cimag(PN5_tail) );
    // return v2*PN0;
    return  v2*(PN2 + 
                v2*(PN4 + 
                    v*(I*ImPN5 + PN5_tail +
                        v*PN6)));
#undef EVALEJ
#undef SQ1M2
#undef EPOW
}

