#define SQ1O70 0.119522860933439363996881717969312498484687910
COMPLEX16 calculate_h43FourierModep(INT p, REAL8 eta, DynParamsCache *dc, PNEllipticEvaluator *pe)
{
    COMPLEX16 ret;
    INT pm = p - 3;
    if (pm==0) return 0.0;
    INT pm2 = pm*pm;
    INT pm3 = pm2*pm;
    INT pm4 = pm2*pm2;
    INT pm5 = pm4*pm;
    REAL8 *ePow = dc->ePow;
    REAL8 *sq1m2Pow = dc->sq1mesqPow;
    REAL8 m1p2eta = -1. + 2.*eta;
    REAL8 y = sq1m2Pow[1];
    REAL8 yp = y+1.0, myp = -y+1.0;
    REAL8 yp2 = yp*yp, myp2 = myp*myp;
    REAL8 yp3 = yp2*yp, myp3 = myp2*myp;
    REAL8 yp4 = yp3*yp, myp4 = myp3*myp;
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
    REAL8 dm = sqrt(1. - 4.*eta);
#define EVALEJ(pp, qq, aa, bb) evaluate_Jpqab((pp), (qq), (aa), (bb), pe)
// #define EVALEJ(p, q, a, b) 1.0
#define SQ1M2(n) sq1m2Pow[n]
#define EPOW(n) ePow[n]
    REAL8 ImPN3, ImPN5, PN6;
    ImPN3 = -2*pm*EVALEJ(pm,pm,0,0)*SQ1M2(1)*(3 + SQ1M2(2)) - 
        EVALEJ(pm,pm,2,0)*SQ1M2(2)*(pm*SQ1M2(1)*(-5 + SQ1M2(2)) + 4*(3 + SQ1M2(2))) + 
        EVALEJ(pm,pm,1,0)*(-2 - 6*SQ1M2(2) - pm*SQ1M2(1)*(5 + 7*SQ1M2(2))) + 
        EVALEJ(pm,pm,3,0)*SQ1M2(2)*(35 + SQ1M2(2) + 20*pm*SQ1M2(3)) + 
        EVALEJ(pm,pm,4,0)*(35 + 33*SQ1M2(2) - 12*pm*SQ1M2(3))*SQ1M2(4) - 
        140*EVALEJ(pm,pm,5,0)*SQ1M2(6) + 60*EVALEJ(pm,pm,6,0)*SQ1M2(8);    
    ImPN3 *= SQ1O70*dm*y*m1p2eta/(6.*ePow[3]);

    ImPN5 = -18*m1p2eta*pm*EVALEJ(pm,pm,0,1)*SQ1M2(1)*(3 + SQ1M2(2)) + 
   9*m1p2eta*EPOW(1)*EVALEJ(-1 + pm,pm,1,0)*(1 + 3*SQ1M2(2)) - 
   9*m1p2eta*EPOW(1)*EVALEJ(1 + pm,pm,1,0)*(1 + 3*SQ1M2(2)) - 
   9*m1p2eta*EVALEJ(pm,pm,2,1)*SQ1M2(2)*
    (pm*SQ1M2(1)*(-5 + SQ1M2(2)) + 4*(3 + SQ1M2(2))) - 
   9*m1p2eta*EVALEJ(pm,pm,1,1)*(2 + 6*SQ1M2(2) + pm*SQ1M2(1)*(5 + 7*SQ1M2(2))) + 
   9*m1p2eta*EVALEJ(pm,pm,3,1)*SQ1M2(2)*(35 + SQ1M2(2) + 20*pm*SQ1M2(3)) + 
   9*m1p2eta*EVALEJ(pm,pm,4,1)*SQ1M2(3)*
    (35*SQ1M2(1) + 33*SQ1M2(3) - 12*pm*SQ1M2(4)) + 
   (EVALEJ(pm,pm,3,0)*SQ1M2(2)*(10*(5982 - 13181*eta + 2502*eta2) + 
        41580*m1p2eta*SQ1M2(1) + 2*(26067 - 51820*eta + 1916*eta2)*SQ1M2(2) + 
        (-84348*m1p2eta + (18066 - 47657*eta + 28260*eta2)*pm)*SQ1M2(3) + 
        22*(129 - 313*eta + 2*eta2 + 1890*m1p2eta*pm)*SQ1M2(4) + 
        (6 + 3837*eta - 5108*eta2)*pm*SQ1M2(5)))/132. + 
   (EVALEJ(pm,pm,1,0)*(-132*(6 - 13*eta + 2*eta2) - 
        66*m1p2eta*(-36 + 5*(-7 + 2*eta)*pm)*SQ1M2(1) + 
        (-6606 + 14632*eta - 3032*eta2 - 10395*m1p2eta*pm)*SQ1M2(2) - 
        11*(-648*m1p2eta + (501 - 1187*eta + 436*eta2)*pm)*SQ1M2(3) - 
        3*(6 + 20*eta + 128*eta2 + 99*m1p2eta*pm)*SQ1M2(4) + 
        (921 - 2309*eta + 68*eta2)*pm*SQ1M2(5)))/66. + 
   EVALEJ(pm,pm,0,0)*(-6*m1p2eta*(-9 + 2*(-5 + eta)*pm)*SQ1M2(1) + 
      108*m1p2eta*pm*SQ1M2(2) - (3*(66 - 132*eta + (221 - 488*eta + 124*eta2)*pm)*
         SQ1M2(3))/11. + 36*m1p2eta*pm*SQ1M2(4) + 
      ((261 - 604*eta + 68*eta2)*pm*SQ1M2(5))/33.) + 
   (EVALEJ(pm,pm,4,0)*SQ1M2(4)*(60*(-3796 + 5537*eta + 5035*eta2) + 
        742500*m1p2eta*SQ1M2(1) + 10*(23631 - 52174*eta + 20612*eta2)*SQ1M2(2) + 
        (374220*m1p2eta + (-209694 + 450883*eta - 47820*eta2)*pm)*SQ1M2(3) - 
        30*(5*(237 - 728*eta + 458*eta2) + 2376*m1p2eta*pm)*SQ1M2(4) + 
        15*(210 - 1313*eta + 2500*eta2)*pm*SQ1M2(5)))/660. - 
   1260*m1p2eta*EVALEJ(pm,pm,5,1)*SQ1M2(6) - 
   (EVALEJ(pm,pm,5,0)*(3*(84614 - 195863*eta + 62860*eta2) + 
        223344*m1p2eta*SQ1M2(1) + (48750 - 66399*eta - 85652*eta2)*SQ1M2(2) + 
        44*(-498 + 961*eta + 420*eta2)*pm*SQ1M2(3))*SQ1M2(6))/132. + 
   (EVALEJ(pm,pm,2,0)*SQ1M2(1)*(-8910*m1p2eta + 
        (-480 + 3262*eta - 4740*eta2)*SQ1M2(1) + 
        660*m1p2eta*(-27 + (-14 + eta)*pm)*SQ1M2(2) - 
        6*(380 - 959*eta + 700*eta2 + 1155*m1p2eta*pm)*SQ1M2(3) + 
        (2970*m1p2eta + (2571 - 4872*eta - 856*eta2)*pm)*SQ1M2(4) + 
        (4*(282 - 688*eta + 131*eta2) - 6534*m1p2eta*pm)*SQ1M2(5) + 
        5*(69 - 188*eta + 64*eta2)*pm*SQ1M2(6)))/66. + 
   540*m1p2eta*EVALEJ(pm,pm,6,1)*SQ1M2(8) + 
   (EVALEJ(pm,pm,6,0)*(341562 - 707689*eta - 35340*eta2 + 71280*m1p2eta*SQ1M2(1) - 
        15*(-714 + 381*eta + 4348*eta2)*SQ1M2(2) + 
        660*(-6 + 11*eta + 12*eta2)*pm*SQ1M2(3))*SQ1M2(8))/132. + 
   3*(-402 + 769*eta + 420*eta2)*EVALEJ(pm,pm,7,0)*SQ1M2(10) - 
   35*(-6 + 11*eta + 12*eta2)*EVALEJ(pm,pm,8,0)*SQ1M2(12);   
    ImPN5 *= SQ1O70*dm/(6.*ePow[3]*y);


    PN6 = (28*pm*EVALEJ(pm,pm,1,0)*(1 + 3*SQ1M2(2)))/15. + 
        (EVALEJ(pm,pm,3,0)*SQ1M2(1)*(-300 + 1925*pm*SQ1M2(1) - 4068*SQ1M2(2) + 
        12879*pm*SQ1M2(3)))/60. + 
        (EVALEJ(pm,pm,5,0)*SQ1M2(3)*(-41635 - 94593*SQ1M2(2) + 21520*pm*SQ1M2(3)))/
        30. + (EVALEJ(pm,pm,2,0)*(168*SQ1M2(1)*(3 + SQ1M2(2)) - 
        31*pm*(-5 + 21*SQ1M2(2) + 12*SQ1M2(4))))/45. + 
        (EVALEJ(pm,pm,6,0)*(12043 + 3673*SQ1M2(2) - 484*pm*SQ1M2(3))*SQ1M2(5))/2. - 
        (EVALEJ(pm,pm,4,0)*SQ1M2(1)*(710 - 8080*SQ1M2(2) + 5129*pm*SQ1M2(3) - 
        3078*SQ1M2(4) + 1979*pm*SQ1M2(5)))/10. - 5998*EVALEJ(pm,pm,7,0)*SQ1M2(7) + 
        1694*EVALEJ(pm,pm,8,0)*SQ1M2(9);
    PN6 *= SQ1O70*dm*eta*y / (6.*ePow[3]);

    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];

    // tail part
    COMPLEX16 PN6_tail;
    COMPLEX16 lnIpvO2 =  pm>0 ? (log(0.5*pm) + 0.5*I*CST_PI) : (log(-0.5*pm) - 0.5*I*CST_PI);
    REAL8 lnxOx0p = log(v2/CONST_X0P);
    COMPLEX16 pref_tail;
    pref_tail = -32. + 45.*lnxOx0p + 30.*lnIpvO2;
    PN6_tail = (-2*pm*EVALEJ(pm,pm,2,0)*SQ1M2(1)*(3 + SQ1M2(2)))/15. + 
        (EVALEJ(pm,pm,5,0)*SQ1M2(2)*(16*(63 + 5*SQ1M2(2)) + 
        7*pm*SQ1M2(1)*(-25 + 53*SQ1M2(2))))/30. - 
        (2*EVALEJ(pm,pm,3,0)*(3 + 9*SQ1M2(2) + 8*pm*SQ1M2(3)))/15. + 
        (7*EVALEJ(pm,pm,7,0)*(-205 - 1143*SQ1M2(2) + 180*pm*SQ1M2(3))*SQ1M2(4))/30. + 
        (EVALEJ(pm,pm,4,0)*(14 - 30*SQ1M2(2) - 24*SQ1M2(4) + 
        pm*(35*SQ1M2(1) + 70*SQ1M2(3) - 9*SQ1M2(5))))/15. - 
        (EVALEJ(pm,pm,6,0)*SQ1M2(2)*(1540 - 826*SQ1M2(2) + 805*pm*SQ1M2(3) - 
        930*SQ1M2(4) + 375*pm*SQ1M2(5)))/30. + 
        (7*EVALEJ(pm,pm,8,0)*(395 + 129*SQ1M2(2) - 12*pm*SQ1M2(3))*SQ1M2(6))/6. - 
        462*EVALEJ(pm,pm,9,0)*SQ1M2(8) + 126*EVALEJ(pm,pm,10,0)*SQ1M2(10);
    PN6_tail *= SQ1O70 * y * m1p2eta * dm * pref_tail / (6.*ePow[3]*pm);

    // print_debug("ImPN3 = %.16e\n", dc->vPow[3]*ImPN3);
    // print_debug("ImPN5 = %.16e\n", dc->vPow[5]*ImPN5);
    // print_debug("PN6 = %.16e\n", dc->vPow[6]*PN6);
    // print_debug("PN6_tail = %.16e, %.16e\n", dc->vPow[6]*creal(PN6_tail), dc->vPow[6]*cimag(PN6_tail) );
    // return v2*PN0;
    return  dc->vPow[3] * (I*ImPN3 + 
                    v2*(I*ImPN5 + 
                        v*(PN6 + PN6_tail)));
#undef EVALEJ
#undef SQ1M2
#undef EPOW
}

