COMPLEX16 calculate_h41FourierModep(INT p, REAL8 eta, DynParamsCache *dc, PNEllipticEvaluator *pe)
{
    COMPLEX16 ret;
    INT pm = p - 1;
    if (pm==0) return 0.0;
    INT pm2 = pm*pm;
    INT pm3 = pm2*pm;
    INT pm4 = pm2*pm2;
    INT pm5 = pm4*pm;
    REAL8 *ePow = dc->ePow;
    REAL8 *sq1m2Pow = dc->sq1mesqPow;
    REAL8 m1p2eta = -1. + 2.*eta;
    REAL8 y = sq1m2Pow[1];
    REAL8 yp = y+1.0, myp = -y+1.0;
    REAL8 yp2 = yp*yp, myp2 = myp*myp;
    REAL8 yp3 = yp2*yp, myp3 = myp2*myp;
    REAL8 yp4 = yp3*yp, myp4 = myp3*myp;
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
    REAL8 dm = sqrt(1. - 4.*eta);
#define EVALEJ(pp, qq, aa, bb) evaluate_Jpqab((pp), (qq), (aa), (bb), pe)
// #define EVALEJ(p, q, a, b) 1.0
#define SQ1M2(n) sq1m2Pow[n]
#define EPOW(n) ePow[n]
    REAL8 ImPN3, ImPN5, PN6;
    ImPN3 = pm*EVALEJ(pm,pm,0,0)*SQ1M2(1) + EVALEJ(pm,pm,1,0)*(1 + (5*pm*SQ1M2(1))/6.) - 
        (25*EVALEJ(pm,pm,3,0)*SQ1M2(2))/6. - 
        (EVALEJ(pm,pm,2,0)*(-4 + 5*pm*SQ1M2(1))*SQ1M2(2))/6. + 
        (5*EVALEJ(pm,pm,4,0)*SQ1M2(4))/2.;    
    ImPN3 *= SQ1O10*dm*y*m1p2eta/(7.*ePow[1]);

    ImPN5 = (1.5 - 3*eta)*EPOW(1)*EVALEJ(-1 + pm,pm,1,0) + 
        (3*m1p2eta*EPOW(1)*EVALEJ(1 + pm,pm,1,0))/2. + 
        3*m1p2eta*pm*EVALEJ(pm,pm,0,1)*SQ1M2(1) + 
        (m1p2eta*EVALEJ(pm,pm,1,1)*(6 + 5*pm*SQ1M2(1)))/2. - 
        (25*m1p2eta*EVALEJ(pm,pm,3,1)*SQ1M2(2))/2. - 
        (m1p2eta*EVALEJ(pm,pm,2,1)*(-4 + 5*pm*SQ1M2(1))*SQ1M2(2))/2. + 
        EVALEJ(pm,pm,1,0)*(6 - 13*eta + 2*eta2 + 
        (m1p2eta*(-12 + 5*(-7 + 2*eta)*pm)*SQ1M2(1))/6. + 
        ((6 + 20*eta + 128*eta2 + 825*m1p2eta*pm)*SQ1M2(2))/132. - 
        ((225 - 493*eta + 20*eta2)*pm*SQ1M2(3))/36.) + 
        EVALEJ(pm,pm,0,0)*(m1p2eta*(-3 + 2*(-5 + eta)*pm)*SQ1M2(1) + 
        (2 - 4*eta)*pm*SQ1M2(2) - ((261 - 604*eta + 68*eta2)*pm*SQ1M2(3))/66.) - 
        (EVALEJ(pm,pm,3,0)*SQ1M2(2)*(30*(526 - 1213*eta + 390*eta2) + 
        13860*m1p2eta*SQ1M2(1) - 2*(-675 - 61*eta + 890*eta2)*SQ1M2(2) + 
        (-7334 + 14783*eta + 900*eta2)*pm*SQ1M2(3)))/792. + 
        (15*m1p2eta*EVALEJ(pm,pm,4,1)*SQ1M2(4))/2. + 
        (EVALEJ(pm,pm,4,0)*(36656 - 76532*eta + 4500*eta2 + 5940*m1p2eta*SQ1M2(1) - 
        30*(-349 + 648*eta + 86*eta2)*SQ1M2(2) + 
        3*(-1150 + 2323*eta + 180*eta2)*pm*SQ1M2(3))*SQ1M2(4))/792. + 
        (EVALEJ(pm,pm,2,0)*SQ1M2(1)*(2970*m1p2eta + 
        6*(-464 + 833*eta + 258*eta2)*SQ1M2(1) - 
        66*m1p2eta*(-27 + 10*(-6 + eta)*pm)*SQ1M2(2) - 
        2*(564 - 1376*eta + 262*eta2 + 495*m1p2eta*pm)*SQ1M2(3) + 
        25*(53 - 124*eta + 16*eta2)*pm*SQ1M2(4)))/396. + 
        ((-46586 + 93977*eta + 6300*eta2)*EVALEJ(pm,pm,5,0)*SQ1M2(6))/792. - 
        (5*(-1150 + 2323*eta + 180*eta2)*EVALEJ(pm,pm,6,0)*SQ1M2(8))/264.;   
    ImPN5 *= SQ1O10*dm/(7.*ePow[1]*y);


    PN6 = (-14*pm*EVALEJ(pm,pm,1,0))/15. + (EVALEJ(pm,pm,3,0)*SQ1M2(1)*
        (20 + 47*pm*SQ1M2(1)))/24. + 
        (EVALEJ(pm,pm,2,0)*(-168*SQ1M2(1) + 31*pm*(-5 + 4*SQ1M2(2))))/90. - 
        (17*EVALEJ(pm,pm,5,0)*SQ1M2(3))/4. + 
        (EVALEJ(pm,pm,4,0)*SQ1M2(1)*(710 - 178*SQ1M2(2) + 43*pm*SQ1M2(3)))/60. - 
        (43*EVALEJ(pm,pm,6,0)*SQ1M2(5))/12.;
    PN6 *= SQ1O10*dm*eta*y / (7.*ePow[1]);

    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];

    // tail part
    COMPLEX16 PN6_tail;
    COMPLEX16 lnIpvO2 =  pm>0 ? (log(0.5*pm) + 0.5*I*CST_PI) : (log(-0.5*pm) - 0.5*I*CST_PI);
    REAL8 lnxOx0p = log(v2/CONST_X0P);
    COMPLEX16 pref_tail;
    pref_tail = -32. + 45.*lnxOx0p + 30.*lnIpvO2;
    PN6_tail = EVALEJ(pm,pm,3,0)/5. + (pm*EVALEJ(pm,pm,2,0)*SQ1M2(1))/15. + 
        (7*EVALEJ(pm,pm,5,0)*(-16 + 5*pm*SQ1M2(1))*SQ1M2(2))/36. + 
        (EVALEJ(pm,pm,4,0)*(-7*pm*SQ1M2(1)*(5 + 3*SQ1M2(2)) + 6*(-7 + 4*SQ1M2(2))))/
        90. - (35*EVALEJ(pm,pm,7,0)*SQ1M2(4))/4. + 
        EVALEJ(pm,pm,6,0)*((55*SQ1M2(2))/9. + (17*SQ1M2(4))/6. - (5*pm*SQ1M2(5))/12.) + 
        (35*EVALEJ(pm,pm,8,0)*SQ1M2(6))/12.;
    PN6_tail *= SQ1O10 * y * m1p2eta * dm * pref_tail / (7.*ePow[1]*pm);

    // print_debug("ImPN3 = %.16e\n", dc->vPow[3]*ImPN3);
    // print_debug("ImPN5 = %.16e\n", dc->vPow[5]*ImPN5);
    // print_debug("PN6 = %.16e\n", dc->vPow[6]*PN6);
    // print_debug("PN6_tail = %.16e, %.16e\n", dc->vPow[6]*creal(PN6_tail), dc->vPow[6]*cimag(PN6_tail) );
    // return v2*PN0;
    return  dc->vPow[3] * (I*ImPN3 + 
                    v2*(I*ImPN5 + 
                        v*(PN6 + PN6_tail)));
#undef EVALEJ
#undef SQ1M2
#undef EPOW
}

COMPLEX16 calculate_h41FourierMode_zeroe(REAL8 eta, DynParamsCache *dc)
{
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
    REAL8 dm = sqrt(1. - 4.*eta);
    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];
#define CPREF 0.3162277660168379331998893544432718533719555139325216826857504853

    REAL8 ImPN3 = CPREF*(1. - 2.*eta)/42.;
    REAL8 ImPN5 = CPREF*(-404. + 1011.*eta - 332.*eta2)/5544.;
    REAL8 PN6 = CPREF*(-73.*eta)/60.;

    REAL8 lnxOx0p = log(v2/CONST_X0P);
    COMPLEX16 lgpref = -32. + 45.*lnxOx0p - 15.*I*CST_PI - 30.*CST_LN2;
    COMPLEX16 PN6_tail = lgpref * CPREF * (-1. + 2.*eta) / 1260.;
    return dm*v2*v*(I*ImPN3 + 
                    v2*(I*ImPN5 + 
                        v*(PN6_tail + PN6)));
#undef CPREF
}


